//! Goal2 binary: two actors, each on its own thread, ping-ponging
//! an empty [`Message`] over `std::sync::mpsc` channels for a
//! caller-supplied duration in seconds, after an optional warmup.
//! Prints messages-handled / throughput, an apparatus-overhead
//! diagnostic, and a `tprobe` band-table report per actor.
//!
//! Unlike goal1, `inner` is fixed at 1: ping-pong keeps at most
//! one message in flight per channel, so batched probe scopes
//! could never fill. If we later add a workload with deeper
//! per-channel queues we'll revisit.
//!
//! Usage: `goal2 --help`

use std::time::Duration;

use actor_x1::runtime::MultiThreadRuntime;
use actor_x1::{Actor, Context, Message};
use clap::Parser;
use tprobe::{self as perf, fmt_commas, pin, ticks};

/// Actor that, on every message received, sends exactly one
/// message back to its configured peer. Same as goal1's but must
/// also be `Send` to cross thread boundaries.
struct PingPongActor {
    peer_id: u32,
}

impl Actor for PingPongActor {
    /// Forward a single `Message` to `self.peer_id`. Never blocks.
    fn handle_message(&mut self, ctx: &mut dyn Context, _msg: Message) {
        ctx.send(self.peer_id, Message);
    }
}

/// CLI for goal2: two-thread two-actor ping-pong with warmup,
/// per-dispatch probe, apparatus-overhead subtraction, and
/// ns-or-ticks band-table report per actor.
#[derive(Parser, Debug)]
#[command(
    version,
    about,
    long_about = None,
    max_term_width = 80,
    before_help = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION")),
)]
struct Cli {
    /// Measurement window in seconds (runs after warmup).
    #[arg(value_parser = parse_non_negative_secs)]
    duration_s: f64,

    /// Warmup duration in seconds before measurement. Runs the
    /// same dispatch loop as the measurement phase (probe active)
    /// so cache / branch-predictor / frequency land in the same
    /// state by the time the probe is cleared and measurement
    /// begins.
    #[arg(short = 'w', long, default_value_t = 0.5, value_parser = parse_non_negative_secs)]
    warmup: f64,

    /// Display probe values as raw ticks instead of nanoseconds.
    #[arg(short = 't', long)]
    ticks: bool,

    /// Fractional precision of numeric cells in the band table.
    /// Omit for a mode-aware default (0 for ticks, 1 for ns) —
    /// typically what you want. Pass an integer N to force N
    /// decimals in either mode.
    #[arg(short = 'd', long)]
    decimals: Option<usize>,

    /// Pin each actor thread to a logical CPU. Accepts a
    /// comma-separated / range list; actor `i` pins to
    /// `pin[i % pin.len()]`. Examples: `--pin 0,1` pairs two
    /// actors to two CPUs; `--pin 0` oversubscribes both onto
    /// one core. Tightens stdev by eliminating OS thread
    /// migration noise.
    #[arg(short = 'p', long)]
    pin: Option<String>,
}

/// `value_parser` helper: reject negative, NaN, and infinite values.
fn parse_non_negative_secs(s: &str) -> Result<f64, String> {
    let v: f64 = s
        .parse()
        .map_err(|e: std::num::ParseFloatError| e.to_string())?;
    if !v.is_finite() || v < 0.0 {
        Err(format!("'{s}' is not a non-negative finite number"))
    } else {
        Ok(v)
    }
}

/// Parse CLI, calibrate apparatus, run two ping-pong actors on
/// their own threads, print summary and per-actor `tprobe`
/// band-table reports.
fn main() {
    let cli = Cli::parse();
    println!("{} {}", env!("CARGO_PKG_NAME"), env!("CARGO_PKG_VERSION"),);

    // Calibrate on main thread before spawning. Matches goal1's
    // calibration code path; actor threads share the same CPU
    // microarchitecture so a single Overhead is good enough.
    let overhead = perf::calibrate();

    let mut rt = MultiThreadRuntime::new("goal2.dispatch");
    let a_id = rt.add_actor(|| PingPongActor { peer_id: 1 });
    let b_id = rt.add_actor(|| PingPongActor { peer_id: 0 });
    assert_eq!((a_id, b_id), (0, 1));
    rt.seed(a_id, Message);

    let warmup = Duration::from_secs_f64(cli.warmup);
    let measurement = Duration::from_secs_f64(cli.duration_s);
    let pin_cores: Vec<usize> = match cli.pin.as_deref() {
        None => vec![],
        Some(spec) => match pin::parse_cores(spec) {
            Ok(cores) => cores,
            Err(e) => {
                eprintln!("error: --pin: {e}");
                std::process::exit(2);
            }
        },
    };
    let results = rt.run(warmup, measurement, &pin_cores);

    let total_count: u64 = results.iter().map(|(c, _)| *c).sum();
    let mmps = total_count as f64 / cli.duration_s / 1e6;
    println!(
        "goal2: {} messages in {:.3}s ({mmps:.3} M msg/s, {n} actors, inner=1)",
        fmt_commas(total_count),
        cli.duration_s,
        n = results.len(),
    );
    let tpn = ticks::ticks_per_ns();
    let framing_ns = overhead.framing_ticks as f64 / tpn;
    let lpi_ns = overhead.loop_per_iter_ticks / tpn;
    let per_event_tk = overhead.per_event_ticks(1);
    let per_event_ns = per_event_tk as f64 / tpn;
    println!(
        "  apparatus: framing={} tk ({:.2} ns); loop_per_iter={:.2} tk ({:.2} ns); per-event at inner=1 = {} tk ({:.2} ns)",
        overhead.framing_ticks,
        framing_ns,
        overhead.loop_per_iter_ticks,
        lpi_ns,
        per_event_tk,
        per_event_ns,
    );
    if pin_cores.is_empty() {
        println!("  pinning: none (unpinned)");
    } else {
        let n = results.len();
        let plan: Vec<String> = (0..n)
            .map(|i| format!("actor{i}→core{}", pin_cores[i % pin_cores.len()]))
            .collect();
        println!("  pinning: {}", plan.join(", "));
    }
    println!();

    for (i, (count, mut probe)) in results.into_iter().enumerate() {
        println!("  actor {i}: handled {} messages", fmt_commas(count));
        probe.report(cli.ticks, Some(&overhead), cli.decimals);
    }
}

//! actor-x1 — an experiment in the actor model in Rust.
//!
//! See `crates/actor-x1/notes/design.md` for the staged design. Stage 1 provides
//! a minimal runtime with two actors that ping-pong an empty
//! [`Message`] for a caller-supplied duration; Goal1 runs both
//! actors on one thread, Goal2 runs each actor on its own thread.
//!
//! Public surface today:
//! - [`Message`]: the empty unit message Stage 1 actors exchange.
//! - [`Actor`]: the single-method actor trait.
//! - [`Context`]: the send-side handle passed to each dispatch.
//! - [`runtime`]: concrete runtimes (single-thread for Goal1; the
//!   multi-thread runtime will land in 0.1.0-3).

pub mod actor_manager;
pub mod pool;
pub mod runtime;
pub mod runtime_zc;

/// Empty unit-type message exchanged between Stage 1 actors.
/// Carries no payload by design — Stage 1's contract is only
/// "dispatch happens"; Stage 2 replaces this with a richer type.
pub struct Message;

/// Actor behavior: handle one [`Message`] at a time, never blocking.
///
/// The only method is [`Actor::handle_message`]; all outbound
/// communication goes through the [`Context`] the runtime supplies.
pub trait Actor {
    /// Handle a single incoming message. Use `ctx` to emit any
    /// resulting sends. Must not block.
    fn handle_message(&mut self, ctx: &mut dyn Context, msg: Message);
}

/// Runtime-supplied send handle passed to each
/// [`Actor::handle_message`] call. Implementations differ between
/// runtimes: the single-thread runtime writes to a shared queue;
/// the (future) multi-thread runtime writes to per-actor channels.
pub trait Context {
    /// Enqueue `msg` for delivery to the actor identified by
    /// `dst_id`. Returns immediately; delivery is the runtime's job.
    fn send(&mut self, dst_id: u32, msg: Message);
}

//! Actor model surface — traits actors implement, plus the
//! catalog that registers and addresses them.
//!
//! This module defines the **what** of the zerocopy actor model:
//!
//! - [`ActorZC`] — the actor trait. One method, one message at
//!   a time.
//! - [`ContextZC`] — the send-side handle the runtime supplies.
//! - [`ActorManager`] — actor catalog. Holds instances and the
//!   probe-name prefix; assigns ids; nothing else.
//!
//! It deliberately knows nothing about the **how** — threads,
//! channels, the pool's lifecycle, or what's being measured —
//! that lives in [`crate::runtime_zc`]. The runtime is one
//! consumer of this surface; future control-plane / discovery
//! actors will be others.

use crate::pool::{BufRefStore, MutexLifo, PoolError, PooledMsg};

/// Actor behavior in the zerocopy runtime.
///
/// - Single method: handle one inbound message at a time;
///   never block.
/// - `msg: &[u8]` is the runtime-owned [`PooledMsg`]'s slice
///   view. The buffer returns to the pool after the handler
///   returns.
/// - Replies are fabricated via [`ContextZC::get_msg`] and
///   forwarded with [`ContextZC::send`].
/// - The trait requires `Send` so actors can ship into
///   spawned threads.
pub trait ActorZC<S: BufRefStore = MutexLifo>: Send {
    /// Handle one inbound message. Use `ctx` to fabricate /
    /// dispatch any outbound messages.
    fn handle_message(&mut self, ctx: &mut dyn ContextZC<S>, msg: &[u8]);
}

/// Send-side handle the runtime supplies to each
/// [`ActorZC::handle_message`] call.
///
/// - Carries access to the shared pool via
///   [`ContextZC::get_msg`].
/// - Dispatches outbound messages to other actors via
///   [`ContextZC::send`].
/// - Drops the `PooledMsg` if the destination channel is
///   closed (peer already shut down) so the buffer never
///   leaks.
pub trait ContextZC<S: BufRefStore = MutexLifo> {
    /// Acquire a buffer of length `size` from the pool.
    /// Forwards [`PoolError`] on failure (`SizeTooLarge` /
    /// `NoMsgs`); the actor handler decides how to react
    /// (typically `expect` for ping-pong workloads).
    fn get_msg(&mut self, size: usize) -> Result<PooledMsg<S>, PoolError>;

    /// Send `msg` to the actor identified by `dst_id`. A
    /// closed channel silently drops the message; the dropped
    /// `PooledMsg`'s buffer returns to the pool.
    fn send(&mut self, dst_id: u32, msg: PooledMsg<S>);
}

/// Actor catalog — registration and lifecycle, nothing else.
///
/// - Holds actor instances and the probe-name prefix.
/// - Hands out `u32` ids on `add`; that's the discovery
///   primitive other actors use as `dst_id` in
///   [`ContextZC::send`].
/// - Drained by a runtime at run time via
///   [`ActorManager::take_actors`]; single-shot for now.
/// - Knows nothing about threads, channels, the pool, or
///   what's being measured.
pub struct ActorManager<S: BufRefStore = MutexLifo> {
    actors: Vec<Box<dyn ActorZC<S> + Send>>,
    probe_name_prefix: String,
}

impl<S: BufRefStore + 'static> ActorManager<S> {
    /// Build an empty manager.
    ///
    /// `probe_name_prefix` is combined with each actor's id by
    /// the runtime to form per-thread probe names (e.g.
    /// `"goalzc.dispatch.actor0"`).
    pub fn new(probe_name_prefix: &str) -> Self {
        Self {
            actors: Vec::new(),
            probe_name_prefix: probe_name_prefix.to_string(),
        }
    }

    /// Register an actor instance.
    ///
    /// - Returns the assigned id (0-indexed; usable as
    ///   `dst_id` in [`ContextZC::send`]).
    /// - The actor must be `Send + 'static`. The trait already
    ///   requires `Send`; `'static` is the usual no-borrow
    ///   bound for moving across threads.
    pub fn add<A: ActorZC<S> + 'static>(&mut self, actor: A) -> u32 {
        let id = self.actors.len() as u32;
        self.actors.push(Box::new(actor));
        id
    }

    /// Drain the registered actors, leaving the manager empty.
    /// Called by the runtime at the start of a run.
    pub fn take_actors(&mut self) -> Vec<Box<dyn ActorZC<S> + Send>> {
        std::mem::take(&mut self.actors)
    }

    /// The probe-name prefix the runtime combines with each
    /// actor's id to name its `TProbe`.
    pub fn probe_name_prefix(&self) -> &str {
        &self.probe_name_prefix
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Trivial actor stub — never invoked by these tests; only
    /// needs to satisfy `ActorZC<S> + Send + 'static` for
    /// `ActorManager::add`.
    struct Noop;

    impl<S: BufRefStore> ActorZC<S> for Noop {
        fn handle_message(&mut self, _ctx: &mut dyn ContextZC<S>, _msg: &[u8]) {}
    }

    /// `take_actors` drains the manager and resets it to
    /// empty so a follow-up registration starts from id 0.
    #[test]
    fn take_actors_drains_and_resets() {
        let mut mgr: ActorManager = ActorManager::new("test.drain-mgr");
        assert_eq!(mgr.add(Noop), 0);
        assert_eq!(mgr.add(Noop), 1);
        let drained = mgr.take_actors();
        assert_eq!(drained.len(), 2);
        // Manager is now empty; new registrations restart from 0.
        assert_eq!(mgr.add(Noop), 0);
    }

    /// `ActorManager::probe_name_prefix` exposes the
    /// caller-supplied prefix verbatim; the runtime composes
    /// `"<prefix>.actor<id>"` for each thread's probe name
    /// (verified end-to-end via `goalzc` output rather than
    /// here, since `TProbe::name` is not on the public
    /// surface).
    #[test]
    fn manager_exposes_probe_name_prefix() {
        let mgr: ActorManager = ActorManager::new("custom.prefix");
        assert_eq!(mgr.probe_name_prefix(), "custom.prefix");
    }
}

